const body = $input.first().json.body || $input.first().json;
const required = ['title', 'category', 'brand_id'];
const missing = required.filter(k => !body[k]);
if (missing.length > 0) return [{ json: { error: true, message: `Missing: ${missing.join(', ')}` } }];

return [{ json: {
  product_id: body.product_id || `prod_${Date.now()}`,
  title: body.title,
  subtitle: body.subtitle || '',
  description: body.description || '',
  category: body.category,
  brand_id: body.brand_id || 'clearstack',
  keywords: body.keywords || [],
  primary_keyword: (body.keywords || [])[0] || body.title,
  price: body.price || 9.99,
  store_urls: {
    etsy: body.etsy_url || '',
    gumroad: body.gumroad_url || '',
    payhip: body.payhip_url || '',
    kdp: body.kdp_url || ''
  },
  cover_image: (body.product_images || [])[0] || body.cover_image || '',
  brand_name: 'ClearStack Studio',
  brand_url: 'https://clearstackstudio.com',
  brand_color_primary: '#1B2A4A',
  brand_color_accent: '#C9A84C',
  wp_domain: 'clearstackstudio.com',
  _received_at: new Date().toISOString()
}}];

const product = $('⚙️ Validate + Build Product Context').first().json;
const brand = $input.first().json.brand || {};
return [{ json: {
  ...product,
  brand,
  tone_description: brand.voice?.description || 'Professional, warm, practical.',
  seo_keywords: [...product.keywords, ...(brand.seo?.etsy_primary_keywords || []).slice(0,5)]
    .filter((v,i,a) => a.indexOf(v)===i).slice(0,15),
  forbidden_phrases: brand.voice?.forbidden_phrases || [],
  signature_phrases: brand.voice?.signature_phrases || [],
  _enriched: true
}}];

values.content:
=Write a complete SEO blog post for this product:

Product: {{$json.title}}
Primary Keyword: {{$json.primary_keyword}}
Keywords: {{$json.seo_keywords.join(', ')}}
Category: {{$json.category}}
Description: {{$json.description}}
Brand Voice: {{$json.tone_description}}
Etsy URL: {{$json.store_urls.etsy}}
Gumroad URL: {{$json.store_urls.gumroad}}
Price: ${{$json.price}}
Forbidden phrases: {{$json.forbidden_phrases.join(', ')}}

Requirements:
- 1800-2200 words total
- H1 title contains primary keyword
- 4-6 H2s with secondary keywords
- Primary keyword appears 5-7 times naturally
- First paragraph hooks AND contains primary keyword
- 2 product CTAs linking to store (use STORE_URL placeholder)
- FAQ section at end (3 Qs — targets featured snippets)
- Real, specific examples — no generic advice
- Conversational but authoritative

Respond ONLY with this JSON:
{
  "wordpress_data": {
    "title": "SEO title — contains primary keyword",
    "slug": "url-slug-with-keyword",
    "meta_description": "155 char meta description with keyword",
    "focus_keyword": "primary keyword",
    "categories": ["Productivity", "Templates"],
    "tags": ["tag1","tag2","tag3","tag4","tag5"],
    "featured_image_alt": "descriptive alt text for product image"
  },
  "content_html": "FULL blog post HTML — use h2, h3, p, ul, li, strong, a href tags. 1800-2200 words. Include all sections. CTAs use STORE_URL placeholder.",
  "excerpt": "2-3 sentence excerpt under 150 chars",
  "pinterest_description": "Pinterest pin description — keyword rich, 400 chars max",
  "estimated_read_time_minutes": 8,
  "word_count": 2000,
  "internal_links_needed": [
    { "placeholder": "INTERNAL_LINK_TOPIC", "suggested_post": "future post title" }
  ]
}

=Create 3 carousel post scripts for this product:

Product: {{$json.title}}
Category: {{$json.category}}
Description: {{$json.description}}
Brand: {{$json.brand_name}}
Tone: {{$json.tone_description}}
Primary Color: {{$json.brand_color_primary}}
Accent Color: {{$json.brand_color_accent}}
Store URL: {{$json.store_urls.etsy || $json.store_urls.gumroad}}
Price: ${{$json.price}}

Create exactly 3 carousels:
1. EDUCATIONAL: "5 ways to use [product]"
2. PROBLEM_SOLUTION: specific pain → this product solves it
3. BEFORE_AFTER: chaotic situation → organized with product

Each carousel = 6-8 slides. Respond ONLY with this JSON:
{
  "carousels": [
    {
      "type": "educational",
      "hook_text": "scroll-stopping first slide headline",
      "platform_caption": {
        "instagram": "IG caption with emojis — 150 words max + hashtags",
        "facebook": "FB post — story driven, 200 words max",
        "pinterest": "Pinterest description — keyword rich, 400 chars"
      },
      "slides": [
        {
          "slide_number": 1,
          "slide_type": "hook",
          "headline": "Max 8 words — the hook",
          "body_text": "Supporting text — max 20 words",
          "emoji": "✨",
          "background_style": "solid_primary",
          "text_color": "white"
        }
      ],
      "final_slide_cta": "CTA for last slide"
    }
  ],
  "hashtag_sets": {
    "instagram_30": "30 hashtags as single string",
    "tiktok_5": "5 hashtags as single string"
  }
}

parameters.jsCode:
const raw = $input.first().json;
const product = $('⚙️ Pass Approved Product').first().json;

let blogData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  blogData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  blogData = { error: true, message: e.message };
}

const primaryUrl = product.store_urls.etsy || product.store_urls.gumroad || product.store_urls.payhip || '#';
const contentHtml = (blogData.content_html || '').replace(/STORE_URL/g, primaryUrl);

return [{ json: {
  title: blogData.wordpress_data?.title || product.title,
  slug: blogData.wordpress_data?.slug || product.title.toLowerCase().replace(/[^a-z0-9]/g, '-'),
  content: contentHtml,
  excerpt: blogData.excerpt || '',
  status: 'draft',
  meta: {
    _yoast_wpseo_title: blogData.wordpress_data?.title,
    _yoast_wpseo_metadesc: blogData.wordpress_data?.meta_description,
    _yoast_wpseo_focuskw: blogData.wordpress_data?.focus_keyword
  },
  categories_names: blogData.wordpress_data?.categories || ['Digital Products'],
  tags_names: blogData.wordpress_data?.tags || [],
  featured_image_alt: blogData.wordpress_data?.featured_image_alt || '',
  pinterest_description: blogData.pinterest_description || '',
  word_count: blogData.word_count || 0,
  internal_links_needed: blogData.internal_links_needed || [],
  wp_domain: product.wp_domain,
  cover_image: product.cover_image,
  store_urls: product.store_urls,
  _product: product
}}];

const raw = $input.first().json;
const product = $('⚙️ Pass Approved Product').first().json;

let carouselData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  carouselData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  carouselData = { carousels: [], error: true };
}

const storeUrl = product.store_urls.etsy || product.store_urls.gumroad || '#';

return (carouselData.carousels || []).map((carousel, i) => ({ json: {
  ...carousel,
  carousel_index: i,
  product_id: product.product_id,
  product_title: product.title,
  brand_color_primary: product.brand_color_primary,
  brand_color_accent: product.brand_color_accent,
  brand_name: product.brand_name,
  store_url: storeUrl,
  hashtag_sets: carouselData.hashtag_sets || {}
}}));

// Build 1080x1080 HTML for every slide in this carousel
const carousel = $input.first().json;
const P = carousel.brand_color_primary || '#1B2A4A';
const A = carousel.brand_color_accent || '#C9A84C';
const B = carousel.brand_name || 'ClearStack Studio';
const STORE = carousel.store_url || '#';

const bgMap = {
  solid_primary: `background:${P};`,
  solid_accent: `background:${A};`,
  gradient: `background:linear-gradient(135deg,${P} 0%,#2D4A7A 100%);`,
  white: `background:#FFF;border:3px solid #F0F0F0;`
};

const slides = carousel.slides || [];
const totalSlides = slides.length;

const slideHTMLs = slides.map((s, i) => {
  const bg = bgMap[s.background_style] || bgMap.solid_primary;
  const tc = s.text_color === 'dark' ? P : '#FFF';
  const sub = s.text_color === 'dark' ? A : 'rgba(255,255,255,0.82)';
  const isLast = i === totalSlides - 1;
  const headlineSize = (s.headline || '').length > 30 ? '54px' : '66px';

  return `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>
*{margin:0;padding:0;box-sizing:border-box;}
body{width:1080px;height:1080px;overflow:hidden;font-family:'Inter','Arial',sans-serif;}
.slide{width:1080px;height:1080px;${bg}display:flex;flex-direction:column;justify-content:center;align-items:center;padding:90px;position:relative;}
.top-bar{position:absolute;top:0;left:0;right:0;height:7px;background:${A};}
.logo{position:absolute;bottom:38px;right:52px;font-size:19px;font-weight:700;color:${sub};letter-spacing:1px;}
.num{position:absolute;bottom:40px;left:52px;font-size:15px;color:${sub};}
.emoji{font-size:76px;margin-bottom:28px;line-height:1;}
.accent-line{width:80px;height:5px;background:${A};border-radius:3px;margin:0 auto 32px;}
.headline{font-size:${headlineSize};font-weight:800;color:${tc};text-align:center;line-height:1.15;margin-bottom:26px;letter-spacing:-0.5px;}
.body{font-size:30px;color:${sub};text-align:center;line-height:1.55;max-width:880px;}
.cta{margin-top:52px;padding:26px 64px;background:${s.background_style==='white'?P:A};color:${s.background_style==='white'?'#FFF':P};font-size:28px;font-weight:700;border-radius:50px;text-decoration:none;}
.swipe{position:absolute;right:28px;top:50%;transform:translateY(-50%);font-size:36px;opacity:0.45;color:${tc};}
</style></head><body>
<div class="slide">
  <div class="top-bar"></div>
  ${s.emoji?`<div class="emoji">${s.emoji}</div>`:''}
  ${i>0?'<div class="accent-line"></div>':''}
  <div class="headline">${s.headline||''}</div>
  ${s.body_text?`<div class="body">${s.body_text}</div>`:''}
  ${isLast&&carousel.final_slide_cta?`<a class="cta" href="${STORE}">${carousel.final_slide_cta}</a>`:''}
  ${!isLast?'<div class="swipe">›</div>':''}
  <div class="logo">${B}</div>
  <div class="num">${i+1} / ${totalSlides}</div>
</div></body></html>`;
});

return [{ json: {
  ...carousel,
  slide_htmls: slideHTMLs,
  slide_count: slideHTMLs.length,
  output_dir: `/tmp/carousel_${carousel.product_id}_${carousel.type}`,
  _html_built: true
}}];

const humanized = $input.first().json;
const original = $('⚙️ Parse Blog → WordPress Payload').first().json;
let content = original.content;
if (humanized.humanized_content && !humanized.parse_error && humanized.quality_score !== 'poor') {
  // Apply humanized paragraphs while preserving HTML heading structure
  const humanParas = humanized.humanized_content.split('\n\n').filter(p=>p.trim().length>40);
  let paraIndex = 0;
  content = content.replace(/<p>([^<]{80,})<\/p>/g, () => {
    const replacement = humanParas[paraIndex] ? `<p>${humanParas[paraIndex].trim()}</p>` : `<p>${arguments[1]}</p>`;
    paraIndex++;
    return replacement;
  });
}
return [{ json: { ...original, content, _humanized: true } }];

