const stdout = $input.first().json.stdout || '';
const renderLine = stdout.split('\n').find(l => l.startsWith('RENDERED|'));
const parts = (renderLine||'').split('|');
const successCount = parseInt(parts[1]) || 0;
const outputDir = parts[2]?.trim() || '';

const slideFiles = Array.from({ length: successCount }, (_, i) =>
  `${outputDir}/slide_${String(i+1).padStart(2,'0')}.png`
);

const carouselData = $('🖥️ Build Slide HTML (1080×1080)').first().json;

return [{ json: {
  ...carouselData,
  rendered_slides: slideFiles,
  render_count: successCount,
  output_dir: outputDir,
  render_ok: successCount > 0
}}];

const wp = $input.first().json;
const blog = $('⚙️ Merge Humanized Blog').first().json;
const product = $('⚙️ Pass Approved Product').first().json;
const postUrl = wp.link || `https://clearstackstudio.com/?p=${wp.id}`;
const canonicalUrl = `https://clearstackstudio.com/blog/${blog.slug}`;
return [{ json: {
  post_id: wp.id,
  post_url: postUrl,
  canonical_url: canonicalUrl,
  title: blog.title,
  meta_description: blog.meta._yoast_wpseo_metadesc,
  pinterest_description: blog.pinterest_description,
  excerpt: blog.excerpt,
  cover_image: product.cover_image,
  store_urls: product.store_urls,
  product_id: product.product_id,
  product_title: product.title
}}];

const carousel = $input.first().json;
const product = $('⚙️ Pass Approved Product').first().json;
const slides = carousel.rendered_slides || [];
const captions = carousel.platform_caption || {};
const storeUrl = product.store_urls.etsy || product.store_urls.gumroad || '#';
const pinToken = product.brand?.social?.pinterest?.access_token || 'YOUR_CLEARSTACK_PINTEREST_TOKEN';
const pinBoards = product.brand?.social?.pinterest?.board_ids || {};

return [
  { json: { platform: 'instagram', media_paths: slides, caption: captions.instagram || '', carousel_type: carousel.type, product_id: carousel.product_id, hashtags: carousel.hashtag_sets?.instagram_30 || '', store_url: storeUrl } },
  { json: { platform: 'facebook', media_paths: slides, caption: captions.facebook || '', carousel_type: carousel.type, product_id: carousel.product_id, store_url: storeUrl } },
  { json: { platform: 'pinterest', media_paths: [slides[0]], caption: captions.pinterest || '', carousel_type: carousel.type, product_id: carousel.product_id, board_id: pinBoards.templates || pinBoards.productivity || 'YOUR_BOARD_ID', link: storeUrl, pin_token: pinToken } }
];

